                    return;
                }

                // Dieu kien 2: Apply button ton tai + Visible + Enabled?
                try
                {
                    Ranorex.Core.Element applyEl;
                    bool applyFound = Host.Local.TryFindSingle(applyBtnPath, 0, out applyEl);

                    if (applyFound && applyEl.Visible && applyEl.Enabled)
