                        Report.Log(ReportLevel.Info, "ApplyBtn_On_Production",
                            string.Format("Vong {0}: Apply Visible+Enabled — click 1 phat", round));
                        repo.InspectionRegionSettings.BtnApplyProductionPresetting.Click();
                        hasClicked = true;
